var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"여기, 맥크레디 부인의 유언장 원본이에요. 확인해 보세요.","JPN":"これがマクレディー夫人の遺言状の原本です。ご確認ください。","ENG":"Here. This is the written will, the original one, that Mrs. MacCready made. See it for yourself.","TWN":"這裡，是麥克蕾蒂夫人的遺囑正本，請您確認一下。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"말도 안 돼......","JPN":"そんな……","ENG":"No way...","TWN":"不會吧……"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아무리 학회에 심취했어도 그렇지 대체 무슨 생각이었던 거야?!","JPN":"いくら学会に心酔していたとしても、いったいどういうつもり！？","ENG":"What was she thinking? Did she really fall that deep into this nonsense?","TWN":"就算再熱衷於學會，也不能這麼做啊，她在想什麼啊？！"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"충격이 크신 것 같네요. 잠시 쉰 다음에 계속 얘기하실래요?","JPN":"ショックが大きいようですね。しばらく休んでから話を続けましょうか？","ENG":"You seem shocked. Do you need some time for yourself?","TWN":"您似乎受到了很大的衝擊呢。我們稍微休息一下再繼續談吧？"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"됐으니까 신경 쓰지 마세요!","JPN":"いいです、気にしないでください！","ENG":"Don't mind me. Go on!","TWN":"不了，不用管我！"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"가문의 재산까지 가로챈 마당에 절 여기로 부른 이유가 뭐죠?","JPN":"マクレディー家の財産まで横取りしたうえで、私をここに呼んだ理由は何ですの？","ENG":"Then why did you want me here? The family assets weren't enough for you?","TWN":"既然妳連我家的財產都私吞了，為什麼還把我叫到這裡來？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>맥크레디 영지는 학회의 소굴이 됐다. 네 자리는 없으니 장례만 마치고 얌전히 사라져라.</color> 그런 뜻인가요?","JPN":"<color=#ffd34c>マクレディーの領地は学会の巣窟となった。お前の居場所は無いから、\\n葬儀が終わったらおとなしく姿を消せ。</color>ということですか？","ENG":"Did you want to tell me to my face that <color=#ffd34c>the MacCready Estate has fallen into the hands of the Society, and that you will leave nothing for me once the funeral is over</color>?","TWN":"<color=#ffd34c>麥克蕾蒂的領地已經變成學會的巢穴。這裡沒有妳的位置，葬禮結束後就乖乖消失吧</color>，是這個意思嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"......그렇지 않아요, 레지나 님.","JPN":"……違いますよ、レジーナ様。","ENG":"That's not the case, Miss Regina.","TWN":"……不是這樣的，蕾佳娜大人。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저흰 이 유산을 받을 생각이 없어요. 상속을 포기하겠다는 신고서도 사전에 작성해 두었답니다.","JPN":"我々はこの遺産を受け取らないつもりです。相続を放棄するという書類も事前に作っておきました。","ENG":"We don't mean to keep the family assets to ourselves. The inheritance disclaimer has already been filled in.","TWN":"我們並不打算接受這份遺產，放棄繼承權的申請書我們也已經事先寫好了。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"날인도 끝냈으니 그대로 변호사에게 보내기만 하면 돼요.","JPN":"捺印もしてあるので、そのまま弁護士に送れば手続きは終わりです。","ENG":"And the document has been signed as well. All you have to do is send it to the attorney.","TWN":"章也蓋了，所以就這樣交給律師就可以了。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"뭐라고요? 어째서......?","JPN":"何ですって？　どうして……？","ENG":"Huh? But why?","TWN":"妳說什麼？怎麼會……？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"말씀드린 대로 레지나 님께서 한 번만 저희를 도와주셨으면 해요.","JPN":"お伝えしたとおり、レジーナ様には一度だけ我々を手伝っていただきたいのです。","ENG":"As said, we'd like for you to do something for us, just once.","TWN":"如我們剛才所說，蕾佳娜大人只要再幫我們一次就行了。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저희 부탁을 들어 주신다면 신고서는 지금 바로 레지나님께 드릴게요.","JPN":"我々の頼みを聞いていただけるのでしたら、書類はすぐにレジーナ様にお渡しします。","ENG":"If you decide to help us, the paper is yours.","TWN":"只要蕾佳娜大人願意聽我們的請求，我們可以現在就將申請書交給您。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"후우......","JPN":"ふう……","ENG":"*Sigh*","TWN":"呼……"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"알겠어요. 일단 들어나 보죠. 대체 무슨 일 때문에 그러는지.","JPN":"分かりましたわ。とりあえず、お聞かせください。いったいどういうことなのかしら。","ENG":"Fine. I'll hear it. What is it about?","TWN":"我知道了。總之先聽聽看吧，究竟是什麼事情？"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"전임 학회장...... 그러니까 어머님의 시신이 도난 당했어요.","JPN":"先代の学会長……つまり、お母様のご遺体が盗まれたのです。","ENG":"The former President's—your mother's body has been stolen.","TWN":"前任學會長……也就是您母親的遺體被人盜走了。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......시, 시신이 도난 당해요?","JPN":"い、遺体が盗まれた……？","ENG":"S-stolen?","TWN":"……遺、遺體被盜了？"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"대체 누가? 어째서?","JPN":"いったい誰が？　どうして？","ENG":"By whom? Why?","TWN":"到底是誰做的？為什麼？"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};